-- Game Foundry Studio DEV database DDL
-- Group: Tags
-- Ownership: docs_build/database/ddl/tags.sql
-- Target DEV database: gamefoundry_dev
-- Scope: executable grouped table DDL for active server API migration.
-- Architecture: Browser -> API -> Database.
-- Flat tags only: no category table, category UI, grouped category filtering, or category-owned seed data.
-- Authoritative key values are generated by the server/API layer unless a later DEV-only seed exception explicitly applies.
-- Owned tables: project_tags, project_tag_assignments
CREATE TABLE IF NOT EXISTS project_tags (
    key text PRIMARY KEY,
    "slug" text NOT NULL,
    "label" text NOT NULL,
    "description" text,
    "active" boolean NOT NULL DEFAULT true,
    "createdAt" timestamptz NOT NULL DEFAULT now(),
    "updatedAt" timestamptz NOT NULL DEFAULT now(),
    "createdBy" text NOT NULL REFERENCES users(key),
    "updatedBy" text NOT NULL REFERENCES users(key)
);

CREATE UNIQUE INDEX IF NOT EXISTS idx_project_tags_slug_unique ON project_tags (lower("slug"));
CREATE INDEX IF NOT EXISTS idx_project_tags_active ON project_tags ("active");
CREATE INDEX IF NOT EXISTS idx_project_tags_createdby ON project_tags ("createdBy");
CREATE INDEX IF NOT EXISTS idx_project_tags_updatedby ON project_tags ("updatedBy");

CREATE TABLE IF NOT EXISTS project_tag_assignments (
    key text PRIMARY KEY,
    "projectKey" text NOT NULL REFERENCES game_workspace_games(key),
    "tagKey" text NOT NULL REFERENCES project_tags(key),
    "createdAt" timestamptz NOT NULL DEFAULT now(),
    "updatedAt" timestamptz NOT NULL DEFAULT now(),
    "createdBy" text NOT NULL REFERENCES users(key),
    "updatedBy" text NOT NULL REFERENCES users(key)
);

CREATE UNIQUE INDEX IF NOT EXISTS idx_project_tag_assignments_project_tag_unique
    ON project_tag_assignments ("projectKey", "tagKey");
CREATE INDEX IF NOT EXISTS idx_project_tag_assignments_projectkey ON project_tag_assignments ("projectKey");
CREATE INDEX IF NOT EXISTS idx_project_tag_assignments_tagkey ON project_tag_assignments ("tagKey");
CREATE INDEX IF NOT EXISTS idx_project_tag_assignments_createdby ON project_tag_assignments ("createdBy");
CREATE INDEX IF NOT EXISTS idx_project_tag_assignments_updatedby ON project_tag_assignments ("updatedBy");
